def solve(arr):
    n = len(arr)
    if n == 0: return 0

    def get_next(sorted_indices):
        res = [None] * n
        stack = []
        for i in sorted_indices:
            while stack and stack[-1] < i:
                res[stack.pop()] = i
            stack.append(i)
        return res

    sorted_indices = sorted(range(n), key=lambda i: (arr[i], i))
    next_higher = get_next(sorted_indices)

    sorted_indices = sorted(range(n), key=lambda i: (-arr[i], i))
    next_lower = get_next(sorted_indices)

    higher, lower = [False] * n, [False] * n
    higher[-1] = lower[-1] = True
    good_starts = 1

    for i in range(n - 2, -1, -1):
        if next_higher[i] is not None:
            higher[i] = lower[next_higher[i]]
        if next_lower[i] is not None:
            lower[i] = higher[next_lower[i]]

        if higher[i]:
            good_starts += 1

    return good_starts

